 4â†’
 5â†’export interface SessionPageData {
 6â†’	session: Session | null;
 7â†’	feedEntries: FeedEntry[];
 8â†’	error: string | null;
 9â†’}
10â†’
11â†’export async function _load(id: string, fetchFn: typeof fetch): Promise<SessionPageData> {
12â†’	try {
13â†’		const res = await fetchFn(`/api/sessions/${id}`);
14â†’		if (res.status === 404) {
15â†’			return { session: null, feedEntries: [], error: `Session '${id}' not found` };
16â†’		}
17â†’		if (!res.ok) {
18â†’			return { session: null, feedEntries: [], error: `Failed to load session (${res.status})` };
19â†’		}
20â†’		const detail: { session: Session; feedEntries: FeedEntry[] } = await res.json();
21â†’		return { session: detail.session, feedEntries: detail.feedEntries, error: null };
22â†’	} catch {
23â†’		return { session: null, feedEntries: [], error: 'Network error loading session' };
24â†’	}
25â†’}
26â†’
27â†’export const load: PageLoad = async ({ params, fetch }) => {
28â†’	return _load(params.id, fetch);
29â†’};
